1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	};
7	
8	export function processScenario(scenario: {
9	  customer: { yearsWithMHPCO: number };
10	  steps: Array<{ op: string; items?: Array<{ type: string }> }>;
11	}): unknown {
12	  const results = scenario.steps.map((step) => {
13	    const items = step.items ?? [];
14	    const policyBasePremium = items.reduce(
15	      (sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0),
16	      0
17	    );
18	    const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
19	    const premium = policyBasePremium + firstInsuranceSurcharge + PROCESSING_FEE;
20	    return { premium };
21	  });
22	  return { results };
23	}
24

